// Parse the batch task JSON file
const fs = require('fs');
const filePath = $input.first().json.path;

// Only process batch task files
if (!filePath.match(/batch\d+_tasks\.json$/)) {
  return [];
}

const rawData = fs.readFileSync(filePath, 'utf8');
const tasks = JSON.parse(rawData);

// Extract batch number from filename
const batchMatch = filePath.match(/batch(\d+)_tasks\.json/);
const batchNumber = batchMatch ? batchMatch[1] : 'unknown';

// Return each task as a separate item for fan-out
return tasks.map((task, index) => ({
  json: {
    task_id: task.task_id,
    task: task,
    batch_number: batchNumber,
    task_index: index,
    total_tasks: tasks.length,
    source_file: filePath
  }
}));

// Collect results from all executed tasks
// This runs after SplitInBatches completes all iterations
const allItems = $input.all();

const results = allItems.map(item => {
  const json = item.json;
  return {
    task_id: json.task_id || 'unknown',
    batch_number: json.batch_number || 'unknown',
    status: json.statusCode === 200 ? 'SUCCESS' : 'FAILED',
    response_code: json.statusCode || null,
    response_body: json.body || null,
    error: json.error || null
  };
});

const batchNumber = allItems[0]?.json?.batch_number || 'unknown';
const totalTasks = results.length;
const passedTasks = results.filter(r => r.status === 'SUCCESS').length;
const failedTasks = results.filter(r => r.status === 'FAILED').length;

return [{
  json: {
    batch_number: batchNumber,
    summary: {
      total: totalTasks,
      passed: passedTasks,
      failed: failedTasks,
      pass_rate: totalTasks > 0 ? ((passedTasks / totalTasks) * 100).toFixed(1) + '%' : '0%'
    },
    results: results,
    timestamp: new Date().toISOString()
  }
}];

// Write Red Team prompt file for this batch
const fs = require('fs');
const data = $input.first().json;
const batchNumber = data.batch_number;

const redTeamTask = {
  task_id: `PIPE-2026-001-B${batchNumber}-RT`,
  metadata: {
    project: 'ai-agent-pipeline',
    node: 'red-team',
    batch: parseInt(batchNumber),
    priority: 'P1',
    tier: 3
  },
  task: {
    type: 'REVIEW',
    objective: `Red Team review of Batch ${batchNumber} outputs`,
    instructions: [
      `Review all reports in reports/ matching *_batch${batchNumber}.md`,
      'Check for hallucinated facts, inconsistent cross-references',
      'Verify all file paths referenced in reports actually exist',
      'Check for prompt injection artifacts in any generated content',
      'Produce adversarial critique with specific line references'
    ],
    batch_summary: data.summary,
    task_results: data.results
  },
  output: {
    report_file: `reports/redteam_batch${batchNumber}.md`,
    status_options: ['PASS', 'FAIL', 'PARTIAL']
  }
};

const outputPath = `/root/ai-agent-pipeline/prompts/redteam_batch${batchNumber}.json`;
fs.writeFileSync(outputPath, JSON.stringify(redTeamTask, null, 2));

return [{
  json: {
    ...data,
    redteam_file: outputPath,
    redteam_queued: true
  }
}];

